import { PremblyPass } from 'prembly-pass';

// Get DOM elements
const launchButton = document.getElementById('launchButton');
const resultSection = document.getElementById('resultSection');
const resultTitle = document.getElementById('resultTitle');
const resultContent = document.getElementById('resultContent');

// Get API key from environment variable
const API_KEY = import.meta.env.VITE_PREMBLY_API_KEY || process.env.PREMBLY_API_KEY;

// Check if API key is available
if (!API_KEY) {
  console.error('PREMBLY_API_KEY environment variable is not set');
  launchButton.disabled = true;
  launchButton.textContent = 'API Key Missing';
  resultSection.style.display = 'block';
  resultSection.className = 'result-section error';
  resultTitle.textContent = 'Error';
  resultContent.textContent = 'PREMBLY_API_KEY environment variable is not set. Please set it and restart the server.';
}

// Initialize PremblyPass
const premblyPass = new PremblyPass({
  app_id: 'test_app_id',
  x_api_key: API_KEY,
  environment: 'test',
  baseUrl: 'https://api.prembly.com',
  config_id: 'test_config_id',
  user_ref: `user_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
});

// Listen for success event
premblyPass.on('success', (data) => {
  console.log('Verification successful:', data);

  // Display success result on screen
  resultSection.style.display = 'block';
  resultSection.className = 'result-section success';
  resultTitle.textContent = 'Verification Successful';
  resultContent.textContent = JSON.stringify(data, null, 2);

  // Re-enable the button
  launchButton.disabled = false;
  launchButton.textContent = 'Launch Verification Widget';
});

// Listen for error event
premblyPass.on('error', (error) => {
  console.error('Verification error:', error);

  // Display error result on screen
  resultSection.style.display = 'block';
  resultSection.className = 'result-section error';
  resultTitle.textContent = 'Verification Error';
  resultContent.textContent = typeof error === 'string' ? error : JSON.stringify(error, null, 2);

  // Re-enable the button
  launchButton.disabled = false;
  launchButton.textContent = 'Launch Verification Widget';
});

// Add event listener to launch button
launchButton.addEventListener('click', () => {
  if (!API_KEY) {
    return;
  }

  // Disable button while widget is open
  launchButton.disabled = true;
  launchButton.textContent = 'Widget Opening...';

  // Hide previous results
  resultSection.style.display = 'none';

  try {
    // Launch the widget
    premblyPass.launch();
  } catch (error) {
    console.error('Failed to launch widget:', error);

    // Re-enable the button
    launchButton.disabled = false;
    launchButton.textContent = 'Launch Verification Widget';

    // Display error
    resultSection.style.display = 'block';
    resultSection.className = 'result-section error';
    resultTitle.textContent = 'Widget Launch Error';
    resultContent.textContent = error.message || 'Failed to launch verification widget';
  }
});

